public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int val) { this.val = val; }
}

public TreeNode canMerge(List<TreeNode> trees) {
    Map<Integer, Integer> leafCount = new HashMap<>();
    Map<Integer, TreeNode> rootMap = new HashMap<>();

    for (TreeNode tree : trees) {
        if (tree.left != null) {
            leafCount.put(tree.left.val, leafCount.getOrDefault(tree.left.val, 0) + 1);
        }
        if (tree.right != null) {
            leafCount.put(tree.right.val, leafCount.getOrDefault(tree.right.val, 0) + 1);
        }
        rootMap.put(tree.val, tree);
    }

    for (TreeNode tree : trees) {
        if (leafCount.getOrDefault(tree.val, 0) == 0) {
            if (isValidBST(tree, 0, 5 * (int)Math.pow(10, 4) + 1, rootMap, leafCount)) {
                return tree;
            }
            break;
        }
    }
    return null;
}

private boolean isValidBST(TreeNode node, int minVal, int maxVal, Map<Integer, TreeNode> rootMap, Map<Integer, Integer> leafCount) {
    if (node == null) {
        return true;
    }
    if (node.val <= minVal || node.val >= maxVal) {
        return false;
    }
    if (rootMap.containsKey(node.left == null ? -1 : node.left.val)) {
        TreeNode leftChild = rootMap.remove(node.left.val);
        leafCount.put(node.left.val, leafCount.get(node.left.val) - 1);
        node.left = leftChild;
    }
    if (rootMap.containsKey(node.right == null ? -1 : node.right.val)) {
        TreeNode rightChild = rootMap.remove(node.right.val);
        leafCount.put(node.right.val, leafCount.get(node.right.val) - 1);
        node.right = rightChild;
    }
    return isValidBST(node.left, minVal, node.val, rootMap, leafCount) && isValidBST(node.right, node.val, maxVal, rootMap, leafCount);
}
